questionvariables.text:
/* V1: Ground-Penetrating Radar (GPR) through soil */
f_val: 100000000.0;
omega_val: 2*%pi*f_val;
sigma_val: 0.01;
epsr_val: 10;
mur_val: 1;
d_val: 2;
R_val: 5;
Pt_dBm: 30;
Gt_dBi: 10;
Gr_dBi: 10;

/* Derived */
eps0: 8.854/10^12;
mu0: 4*%pi/10^7;
eps_val: epsr_val*eps0;
mu_val: mur_val*mu0;

/* Loss tangent */
loss_tangent: sigma_val/(omega_val*eps_val);

/* Classification */
class_opts: random_permutation([[1, false, "Good conductor"], [2, false, "Low-loss dielectric"], [3, true, "Quasi-conductor"]]);

/* Attenuation constant (general formula) */
alpha_val: omega_val*sqrt(mu_val*eps_val/2)*sqrt(sqrt(1 + (sigma_val/(omega_val*eps_val))^2) - 1);

/* Power attenuation through material */
atten_dB: float(8.686*alpha_val*d_val);

/* FSPL */
lambda_val: 3*10^8/f_val;
FSPL_dB: float(20*log(4*%pi*R_val/lambda_val)/log(10));

/* Link budget */
Pr_dBm: float(Pt_dBm + Gt_dBi + Gr_dBi - FSPL_dB - atten_dB);

/* MCQ-MA */
mcq_opts: random_permutation([[1, true, "Double the transmit power (+3 dB)"], [2, false, "Move to 1 GHz for better resolution (increases both alpha and FSPL)"], [3, true, "Use a higher-gain antenna (+3 dBi each gives +6 dB total)"], [4, false, "Reduce material thickness by half (may not be possible for GPR)"], [5, false, "Switch to a lower frequency (reduces alpha but increases antenna size)"]]);
correct_mcq: {1,3};

/* Teacher answers */
ta_class: class_opts;
ta_alpha: float(alpha_val);
ta_atten: float(atten_dB);
ta_FSPL: float(FSPL_dB);
ta_Pr: float(Pr_dBm);
ta_mcq: correct_mcq;

